      const clipped = Math.tanh(x * amount);
      const folded = Math.sin(clipped * (1.2 + state.crush * 1.5));
      curve[i] = clipped * (1 - state.crush * 0.36) + folded * state.crush * 0.28;
    }
    return curve;
  };

  const makeNoiseBuffer = () => {
    const buffer = audio.createBuffer(1, Math.floor(audio.sampleRate * 0.55), audio.sampleRate);
    const data = buffer.getChannelData(0);
    let last = 0;
    for (let i = 0; i < data.length; i += 1) {
      last = last * 0.08 + (Math.random() * 2 - 1) * 0.92;
      data[i] = last;
    }
    return buffer;
  };

  const noiseBuffer = makeNoiseBuffer();

  const track = (seconds, ...nodes) => {
    nodes.forEach((node) => liveNodes.add(node));
    const timer = setTimeout(() => {
      cleanupTimers.delete(timer);
      nodes.forEach((node) => {
        try { if (typeof node.disconnect === 'function') node.disconnect(); } catch (_) {}
        liveNodes.delete(node);
      });
    }, Math.max(100, seconds * 1000 + 180));
    cleanupTimers.add(timer);
  };

  const syncAudio = () => {
    shaper.curve = makeDriveCurve();
    shaper.oversample = '2x';
    master.gain.setTargetAtTime(state.enabled ? state.volume : 0, audio.currentTime, 0.025);
    rumbleBus.gain.setTargetAtTime(0.2 + state.rumble * 0.58, audio.currentTime, 0.04);
    hatBus.gain.setTargetAtTime(0.08 + state.hats * 0.38, audio.currentTime, 0.04);
    rumbleFeedback.gain.setTargetAtTime(0.18 + state.rumble * 0.42, audio.currentTime, 0.04);
    rumbleTone.frequency.setTargetAtTime(95 + state.rumble * 210, audio.currentTime, 0.04);
  };

  const playKick = (time, velocity) => {
    const t = Math.max(time, audio.currentTime + 0.001);
    const length = 0.18 + state.rumble * 0.13;
    const osc = audio.createOscillator();
    const click = audio.createBufferSource();
    const clickFilter = audio.createBiquadFilter();
    const kickGain = audio.createGain();
    const clickGain = audio.createGain();
    const low = audio.createBiquadFilter();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(148 + velocity * 24, t);
    osc.frequency.exponentialRampToValueAtTime(42, t + length);
    low.type = 'lowpass';
    low.frequency.value = 720;
    kickGain.gain.setValueAtTime(0.0001, t);
    kickGain.gain.exponentialRampToValueAtTime(1.1 * velocity, t + 0.004);
    kickGain.gain.exponentialRampToValueAtTime(0.0001, t + length);

    click.buffer = noiseBuffer;
    clickFilter.type = 'highpass';
    clickFilter.frequency.value = 5800;
    clickGain.gain.setValueAtTime(0.18 * velocity, t);
    clickGain.gain.exponentialRampToValueAtTime(0.0001, t + 0.018);

    osc.connect(low);
    low.connect(kickGain);
    kickGain.connect(drumBus);
    kickGain.connect(rumbleBus);
    click.connect(clickFilter);
    clickFilter.connect(clickGain);
    clickGain.connect(drumBus);
    osc.start(t);
    click.start(t);
    osc.stop(t + length + 0.04);
    click.stop(t + 0.05);
    track(length + 0.08, osc, click, clickFilter, kickGain, clickGain, low);
  };

  const playClap = (time, velocity) => {
    const t = Math.max(time, audio.currentTime + 0.001);
    const output = audio.createGain();
    const filter = audio.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 1700 + state.crush * 1100;
    filter.Q.value = 0.8;
    output.connect(drumBus);
    filter.connect(output);
    [0, 0.012, 0.025].forEach((offset, index) => {
      const src = audio.createBufferSource();
      const gain = audio.createGain();
      src.buffer = noiseBuffer;
      gain.gain.setValueAtTime(0.0001, t + offset);
      gain.gain.exponentialRampToValueAtTime((0.18 - index * 0.03) * velocity, t + offset + 0.004);
      gain.gain.exponentialRampToValueAtTime(0.0001, t + offset + 0.075);
      src.connect(gain);
      gain.connect(filter);
      src.start(t + offset);
      src.stop(t + offset + 0.12);
      track(0.18, src, gain);
    });
    track(0.2, output, filter);
  };

  const playHat = (time, velocity, open = false) => {
    const t = Math.max(time, audio.currentTime + 0.001);
    const length = open ? 0.17 : 0.038 + state.hats * 0.035;
    const src = audio.createBufferSource();
    const high = audio.createBiquadFilter();
    const peak = audio.createBiquadFilter();
    const gain = audio.createGain();
    src.buffer = noiseBuffer;
    high.type = 'highpass';
    high.frequency.value = 6200 + state.crush * 2400;
    peak.type = 'peaking';
    peak.frequency.value = 9000;
    peak.Q.value = 1.8;
    peak.gain.value = 3 + state.hats * 7;
    gain.gain.setValueAtTime(0.0001, t);
    gain.gain.exponentialRampToValueAtTime((open ? 0.2 : 0.105) * velocity * state.hats, t + 0.003);
    gain.gain.exponentialRampToValueAtTime(0.0001, t + length);
    src.connect(high);
    high.connect(peak);
    peak.connect(gain);
    gain.connect(hatBus);
    src.start(t);
    src.stop(t + length + 0.04);
    track(length + 0.08, src, high, peak, gain);
  };

  const playPerc = (time, velocity) => {
    const t = Math.max(time, audio.currentTime + 0.001);
    const osc = audio.createOscillator();
    const filter = audio.createBiquadFilter();
    const gain = audio.createGain();
    osc.type = 'square';
    osc.frequency.setValueAtTime(180 + (currentStep % 5) * 72, t);
    filter.type = 'bandpass';
    filter.frequency.value = 620 + (currentStep % 7) * 190;
    filter.Q.value = 5 + state.crush * 9;
    gain.gain.setValueAtTime(0.0001, t);
    gain.gain.exponentialRampToValueAtTime(0.11 * velocity, t + 0.005);
    gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.06);
    osc.connect(filter);
    filter.connect(gain);
    gain.connect(drumBus);
    osc.start(t);
    osc.stop(t + 0.08);
    track(0.12, osc, filter, gain);
  };

  const onTick = ({ step, time, duration }) => {
    if (destroyed) return;
    if (Number.isFinite(duration) && duration > 0) stepSeconds = duration;
    currentStep = ((step % 16) + 16) % 16;
    render();
    if (!state.enabled) return;

    const pattern = patterns[state.pattern] || patterns[0];
    rumbleDelay.delayTime.setTargetAtTime(stepSeconds * (1.34 + state.rumble * 0.56), audio.currentTime, 0.03);
    const t = time;
    if (pattern.kick[currentStep]) playKick(t, pattern.kick[currentStep]);
    if (pattern.clap[currentStep]) playClap(t + 0.004, pattern.clap[currentStep]);
    if (pattern.hat[currentStep]) playHat(t, pattern.hat[currentStep], currentStep % 8 === 7 || currentStep === 15);
    if (pattern.perc[currentStep]) playPerc(t + stepSeconds * 0.02, pattern.perc[currentStep]);
  };

  ctx.domRoot.innerHTML = `
    <style>
      :host { display: block; height: 100%; }
      .hard {
        box-sizing: border-box;
        height: 100%;
        min-width: 300px;
        min-height: 230px;
        display: grid;
        grid-template-rows: auto auto auto 1fr;
        gap: 8px;
        padding: 10px;
        overflow: hidden;
        color: #f8fafc;
        background:
          linear-gradient(135deg, rgba(7, 7, 8, 0.98), rgba(18, 12, 13, 0.98) 58%, rgba(8, 8, 12, 0.98)),
          repeating-linear-gradient(90deg, rgba(248, 113, 113, 0.08) 0 1px, transparent 1px 18px);
        border: 1px solid rgba(248, 113, 113, 0.62);
        border-radius: 8px;
        font: 11px/1.25 ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      }
      .top {
        display: grid;
        grid-template-columns: 1fr auto;
        align-items: center;
        gap: 8px;
      }
      h2 {
        margin: 0;
        color: #fecaca;
        font: 700 13px/1 ui-sans-serif, system-ui, sans-serif;
        letter-spacing: 0;
      }
      .sub {
        margin-top: 2px;
        color: #94a3b8;
        font-size: 9px;
      }
      button,
      select,
      input {
        font: inherit;
      }
      button {
        height: 27px;
        min-width: 50px;
        color: #190707;
        background: #f87171;
        border: 1px solid rgba(254, 202, 202, 0.72);
        border-radius: 5px;
        cursor: pointer;
      }
      button.off {
        color: #cbd5e1;
        background: rgba(15, 23, 42, 0.82);
        border-color: rgba(148, 163, 184, 0.42);
      }
      .controls {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 6px 10px;
      }
      label {
        min-width: 0;
        display: grid;
        grid-template-columns: 48px minmax(0, 1fr) 34px;
        align-items: center;
        gap: 6px;
        color: #cbd5e1;
      }
      input[type="range"] {
        min-width: 0;
        width: 100%;
        accent-color: #f87171;
      }
      .pattern {
        display: grid;
        grid-template-columns: 48px minmax(0, 1fr);
        align-items: center;
        gap: 6px;
        color: #cbd5e1;
      }
      select {
        min-width: 0;
        height: 24px;
        color: #fee2e2;
        background: rgba(2, 6, 23, 0.72);
        border: 1px solid rgba(248, 113, 113, 0.42);
        border-radius: 5px;
      }
      .grid {
        min-height: 0;
        display: grid;
        grid-template-rows: repeat(4, minmax(0, 1fr));
        gap: 5px;
      }
      .row {
        display: grid;
        grid-template-columns: 38px repeat(16, minmax(7px, 1fr));
        gap: 3px;
      }
      .name {
        display: grid;
        align-items: center;
        color: #94a3b8;
        font-size: 9px;
      }
      .cell {
        border: 1px solid rgba(148, 163, 184, 0.18);
        background: rgba(15, 23, 42, 0.82);
        border-radius: 3px;
        opacity: 0.42;
      }
      .cell.on.kick { background: #ef4444; border-color: rgba(252, 165, 165, 0.8); }
      .cell.on.clap { background: #f97316; border-color: rgba(253, 186, 116, 0.78); }
      .cell.on.hat { background: #eab308; border-color: rgba(254, 240, 138, 0.78); }
      .cell.on.perc { background: #a855f7; border-color: rgba(216, 180, 254, 0.78); }
      .cell.play {
        opacity: 1;
        transform: translateY(-1px);
        box-shadow: 0 0 12px rgba(248, 113, 113, 0.72);
      }
    </style>
    <div class="hard">
      <div class="top">
        <div>
          <h2>Hard Techno</h2>
          <div class="sub">distorted kick, rumble, hats, industrial hits</div>
        </div>
        <button id="enabled" type="button"></button>
      </div>
      <div class="controls">
        <label>vol <input id="volume" type="range" min="0" max="1.1" step="0.01"><span id="volumeVal"></span></label>
        <label>drive <input id="drive" type="range" min="0" max="1" step="0.01"><span id="driveVal"></span></label>
        <label>rumble <input id="rumble" type="range" min="0" max="1" step="0.01"><span id="rumbleVal"></span></label>
        <label>hats <input id="hats" type="range" min="0" max="1" step="0.01"><span id="hatsVal"></span></label>
        <label>crush <input id="crush" type="range" min="0" max="1" step="0.01"><span id="crushVal"></span></label>
      </div>
      <div class="pattern">
        <span>mode</span>
        <select id="pattern">
          <option value="0">drive</option>
          <option value="1">industrial</option>
          <option value="2">warehouse</option>
        </select>
      </div>
      <div id="grid" class="grid"></div>
    </div>
  `;

  const $ = (selector) => ctx.domRoot.querySelector(selector);
  const enabledButton = $('#enabled');
  const patternSelect = $('#pattern');
  const gridEl = $('#grid');
  const sliders = {
    volume: $('#volume'),
    drive: $('#drive'),
    rumble: $('#rumble'),
    hats: $('#hats'),
    crush: $('#crush')
  };
  const valueEls = {
    volume: $('#volumeVal'),
    drive: $('#driveVal'),
    rumble: $('#rumbleVal'),
    hats: $('#hatsVal'),
    crush: $('#crushVal')
  };

  const renderGrid = () => {
    const pattern = patterns[state.pattern] || patterns[0];
    const rows = [
      ['kick', 'kick', pattern.kick],
      ['clap', 'clap', pattern.clap],
      ['hat', 'hat', pattern.hat],
      ['perc', 'perc', pattern.perc]
    ];
    gridEl.innerHTML = rows.map(([label, className, row]) => `
      <div class="row">
        <div class="name">${label}</div>
        ${row.map((value, index) => `<div class="cell ${className} ${value ? 'on' : ''} ${index === currentStep ? 'play' : ''}"></div>`).join('')}
      </div>
    `).join('');
  };

  const render = () => {
    enabledButton.textContent = state.enabled ? 'on' : 'off';
    enabledButton.classList.toggle('off', !state.enabled);
    patternSelect.value = String(state.pattern);
    Object.entries(sliders).forEach(([key, input]) => {
      if (input.value !== String(state[key])) input.value = String(state[key]);
      valueEls[key].textContent = state[key].toFixed(2);
    });
    renderGrid();
  };

  const onEnabled = () => {
    state.enabled = !state.enabled;
    syncAudio();
    render();
  };

  const onPattern = () => {
    state.pattern = clamp(Number(patternSelect.value), 0, patterns.length - 1);
    render();
  };

  const sliderHandlers = Object.fromEntries(Object.keys(sliders).map((key) => [key, () => {
    state[key] = Number(sliders[key].value);
    syncAudio();
    render();
  }]));

  enabledButton.addEventListener('click', onEnabled);
  patternSelect.addEventListener('change', onPattern);
  Object.entries(sliderHandlers).forEach(([key, handler]) => sliders[key].addEventListener('input', handler));

  const unsubscribeClock = ctx.clock.onTick(onTick);
  syncAudio();
  render();

  return {
    update() {},
    getState() {
      return { ...state };
    },
    destroy() {
      destroyed = true;
      unsubscribeClock();
      enabledButton.removeEventListener('click', onEnabled);
      patternSelect.removeEventListener('change', onPattern);
      Object.entries(sliderHandlers).forEach(([key, handler]) => sliders[key].removeEventListener('input', handler));
      cleanupTimers.forEach((timer) => clearTimeout(timer));
      cleanupTimers.clear();
      for (const node of liveNodes) {
        try { if (typeof node.stop === 'function') node.stop(); } catch (_) {}
        try { if (typeof node.disconnect === 'function') node.disconnect(); } catch (_) {}
      }
      liveNodes.clear();
      try {
        master.disconnect(); drumBus.disconnect(); rumbleBus.disconnect(); hatBus.disconnect();
        shaper.disconnect(); compressor.disconnect(); rumbleDelay.disconnect(); rumbleFeedback.disconnect(); rumbleTone.disconnect();
      } catch (_) {}
    }
  };
}
